// Hand-written gRPC message types for ClientLimitService.
// These are not generated by protoc.
package clientpb

// ClientLimitResponse holds the transaction limits for a client.
type ClientLimitResponse struct {
	Id            int64  `json:"id"`
	ClientId      int64  `json:"client_id"`
	DailyLimit    string `json:"daily_limit"`
	MonthlyLimit  string `json:"monthly_limit"`
	TransferLimit string `json:"transfer_limit"`
	SetByEmployee int64  `json:"set_by_employee"`
}

// GetClientLimitRequest requests the limits for a client by ID.
type GetClientLimitRequest struct {
	ClientId int64 `json:"client_id"`
}

// SetClientLimitRequest sets the limits for a client.
type SetClientLimitRequest struct {
	ClientId      int64  `json:"client_id"`
	DailyLimit    string `json:"daily_limit"`
	MonthlyLimit  string `json:"monthly_limit"`
	TransferLimit string `json:"transfer_limit"`
	SetByEmployee int64  `json:"set_by_employee"`
}
